alter table public.cb_ai_settings
  add column if not exists guided_service_options text not null default 'FLUXO GUIADO POR SERVIÇO: quando o cliente demonstrar interesse em um serviço, ofereça opções numeradas curtas e permita resposta livre. IA / Chatbot: 1️⃣ Vendas 2️⃣ Suporte 3️⃣ Agendamentos 4️⃣ Dúvidas frequentes 5️⃣ Quero explicar melhor. Sistemas / Apps: 1️⃣ Site profissional 2️⃣ Sistema com login/painel 3️⃣ App/PWA 4️⃣ Loja virtual 5️⃣ Quero explicar melhor. Dashboards / Dados: 1️⃣ Power BI 2️⃣ Planilhas automáticas 3️⃣ Indicadores financeiros 4️⃣ Relatórios gerenciais 5️⃣ Quero explicar melhor. Marketing / Instagram: 1️⃣ Posts e artes 2️⃣ Stories 3️⃣ Reels/vídeos 4️⃣ Gestão de conteúdo 5️⃣ Quero explicar melhor. Hardware / Suporte: 1️⃣ Computador lento 2️⃣ Formatação/limpeza 3️⃣ Rede/Wi-Fi/firewall 4️⃣ Upgrade SSD/RAM 5️⃣ Quero explicar melhor. Se o cliente responder número, interprete a escolha no contexto do serviço. Se responder 5 ou explicar melhor, peça uma descrição livre. Nunca envie mais de um bloco de opções por mensagem.';

update public.cb_ai_settings
set guided_service_options = 'FLUXO GUIADO POR SERVIÇO: quando o cliente demonstrar interesse em um serviço, ofereça opções numeradas curtas e permita resposta livre. IA / Chatbot: 1️⃣ Vendas 2️⃣ Suporte 3️⃣ Agendamentos 4️⃣ Dúvidas frequentes 5️⃣ Quero explicar melhor. Sistemas / Apps: 1️⃣ Site profissional 2️⃣ Sistema com login/painel 3️⃣ App/PWA 4️⃣ Loja virtual 5️⃣ Quero explicar melhor. Dashboards / Dados: 1️⃣ Power BI 2️⃣ Planilhas automáticas 3️⃣ Indicadores financeiros 4️⃣ Relatórios gerenciais 5️⃣ Quero explicar melhor. Marketing / Instagram: 1️⃣ Posts e artes 2️⃣ Stories 3️⃣ Reels/vídeos 4️⃣ Gestão de conteúdo 5️⃣ Quero explicar melhor. Hardware / Suporte: 1️⃣ Computador lento 2️⃣ Formatação/limpeza 3️⃣ Rede/Wi-Fi/firewall 4️⃣ Upgrade SSD/RAM 5️⃣ Quero explicar melhor. Se o cliente responder número, interprete a escolha no contexto do serviço. Se responder 5 ou explicar melhor, peça uma descrição livre. Nunca envie mais de um bloco de opções por mensagem.'
